#!/usr/bin/env python3
from pathlib import Path
import base64,gzip
root=Path(__file__).resolve().parents[1]
FILES={
'webroot/v14.js':'','webroot/index.html':'','webroot/environment.js':'',
}
for rel,enc in FILES.items():
 p=root/rel; p.parent.mkdir(parents=True,exist_ok=True); p.write_bytes(gzip.decompress(base64.b64decode(enc + '=' * (-len(enc) % 4))))
print("materialized part3")
